SELECT COUNT(question_id) AS total_questions
FROM questions
WHERE round_id = (SELECT round_id FROM rounds WHERE round_name = 'Jeopardy!');

SELECT correct_count AS correct_answers
FROM question_success
WHERE question_id = 0;

SELECT difficulty_level
FROM question_difficulty
WHERE question_id = 0;

SELECT correct_count 
FROM question_success 
WHERE question_id = 0;
